test "error_handling_invalid_syntax" {
    // Parsing invalid syntax should produce a tree with error nodes.
    const _result_json = try tree_sitter_language_pack.process("function function function @@@ %%%", "{\"language\":\"javascript\"}");
    defer std.heap.c_allocator.free(_result_json);
}

test "error_process_empty_source" {
    // Process empty source code succeeds with zero metrics
    var gpa: std.heap.DebugAllocator(.{}) = .init;
    defer _ = gpa.deinit();
    const allocator = gpa.allocator();

    const _result_json = try tree_sitter_language_pack.process("", "{\"language\":\"python\"}");
    defer std.heap.c_allocator.free(_result_json);
    var _parsed = try std.json.parseFromSlice(std.json.Value, allocator, _result_json, .{});
    defer _parsed.deinit();
    const result = &_parsed.value;
    try testing.expectEqual(0, result.object.get("metrics").?.object.get("total_lines").?.integer);
}
